Exit fullscreen mode

Y luego, dentro de la vista principal:

if (isLoading) return <SkeletonList />;
if (items.length === 0) {
return (
<EmptyState
title="No hay elementos todavía"
message="Crea el primero o ajusta los filtros para ver resultados."
actionLabel="Crear elemento"
onAction={() => openCreateModal()}
/>
);
}
return <ItemsTable items={items} />;

